<template>
  <div v-if="song" id="songView">
    <div class="song-options">
      <template v-if="editable">
        <button class="orange" @click="toggleEdit">
          {{ $t("cancel") }}
        </button>
        <button class="green" @click="updateSong">
          {{ $t("save") }}
        </button>
        <button class="red" @click="deleteSong">
          {{ $t("delete") }}
        </button>
        <button v-if="!song.traduction" @click="song.traduction = ' '">
          {{ $t("add_translation") }}
        </button>
        <button v-else @click="delete song.traduction">
          {{ $t("remove_translation") }}
        </button>
        <button class="" v-if="!song.phonetic" @click="song.phonetic = ' '">
          {{ $t("add_phonetic") }}
        </button>
        <button v-else @click="delete song.phonetic">
          {{ $t("remove_phonetic") }}
        </button>
      </template>
      <template v-else>
        <button @click="toggleEdit">
          {{ $t("edit") }}
        </button>
        <span>
          <span
            v-if="songVersions.hasPrevious()"
            @click="songVersions.previous()"
          >
            {{ $t("previous_version") }}
          </span>
          <span v-if="songVersions.hasNext()" @click="songVersions.next()">
            {{ $t("next_version") }}
          </span>
        </span>
      </template>
    </div>
    <div class="song">
      <div class="left">
        <EditableDiv class="title" :editable="editable" v-model="song.title" />

        <EditableDiv
          class="description"
          :editable="editable"
          v-model="song.description"
        />

        <div class="main">
          <div class="lyrics">
            <LyricsEditor />
          </div>

          <EditableDiv
            v-if="song.phonetic"
            class="phonetic"
            :editable="editable"
            v-model="song.phonetic"
          />

          <EditableDiv
            v-if="song.traduction"
            class="traduction"
            :editable="editable"
            v-model="song.traduction"
          />
        </div>
      </div>
      <div class="right" v-if="editable || song.getVoices().length > 0">
        <NotesSelect />
      </div>

      <div class="footer">{{ pageComp }}</div>
    </div>
    <div></div>
  </div>
</template>

<script>
import NotesSelect from "../components/NotesSelect.vue";
import LyricsEditor from "../components/LyricsEditor.vue";
import EditableDiv from "../components/EditableDiv.vue";
import Swal from "sweetalert2";
import JsonBin from "../classes/JsonBin";
import { computed } from "vue";

export default {
  name: "Song",
  components: {
    NotesSelect,
    LyricsEditor,
    EditableDiv,
  },
  props: ["page"],
  data() {
    return {
      songVersions: false,
      editable: false,
    };
  },
  provide() {
    return {
      song: computed(() => this.song),
      editable: computed(() => this.editable),
    };
  },
  created() {
    this.getSong();
  },
  watch: {
    $route(route) {
      if (route.name === "song") {
        this.getSong();
        this.editable = false;
      }
    },
  },
  computed: {
    pageComp() {
      if (this.page) return this.page;
      return this.$root.songs.findIndex((e) => e.title === this.song.title) + 1;
    },
    id() {
      return this.$route.params.id;
    },
    song() {
      if (!this.songVersions) return false;
      return this.editable
        ? this.songVersions.altered
        : this.songVersions.versioning;
    },
  },
  methods: {
    toggleEdit() {
      this.songVersions.initChange();
      this.editable = !this.editable;
    },
    getSong() {
      if (this.id) {
        JsonBin.getSong(this.id, (res, version) => {
          this.songVersions = version;
        });
      }
    },
    updateSong() {
      if (this.songVersions.hasChanged()) {
        JsonBin.renameSong(this.id, this.song.title, () => {
          JsonBin.updateSong(this.id, this.songVersions, (res, version) => {
            this.songVersions = version;
          });
        });
      }
      this.editable = false;
    },
    deleteSong() {
      Swal.fire({
        position: "top",
        title: "Cette option n'est pas réversible !",
        html: `Continuer la suppresison de <span>${this.song.title}</span> ?`,
        icon: "warning",
        showCancelButton: true,
        cancelButtonColor: "#3498db",
        confirmButtonColor: "#e74c3c",
        confirmButtonText: "Supprimer",
        cancelButtonText: "Annuler",
        reverseButtons: true,
      }).then((result) => {
        if (result.isConfirmed) {
          JsonBin.deleteSong(this.id, (res) => {
            delete this.$root.songs[res.metadata.id];
            this.$router.push({ name: "home" });
          });
        }
      });
    },
    beforeUnmount() {
      this.songLoaded = false;
    },
  },
};
</script>

