import Voices from "./Voices";

export default class Song {
  constructor({
    title,
    description = undefined,
    lead = undefined,
    voices = {},
    lyrics = undefined,
    traduction = undefined,
    version = undefined,
  }) {
    this.title = title;
    this.description = description;
    this.lead = lead;
    this.lyrics = lyrics;
    this.traduction = traduction;
    this.versions = version;
    this.voices = {};
    for (const voice in Voices) {
      this.voices[voice] = {
        note: voices[voice] ? voices[voice].note : "",
        buzz: voices[voice] ? voices[voice].buzz : false,
        link: voices[voice] ? voices[voice].link : "",
      };
    }
  }

  getVoices() {
    return Object.entries(this.voices)
      .filter((v) => v[1].note)
      .map((v) => v[0]);
  }
}
