<template>
  <div class="notes">
    <template v-for="(value, voice) in song.voices" :key="voice">
      <transition>
        <div
          v-if="editable || value.note"
          :class="['couple', song.lead == voice ? 'lead' : false]"
        >
          <div :class="{ note: true, editable }">
            <select
              v-if="editable"
              :value="value.note"
              @input="value.note = $event.target.value"
            >
              <option value=""></option>
              <option
                v-for="(freq, note) in $notes[0]"
                :key="note"
                :value="note"
              >
                {{ $t(`note.${note}`) }}
              </option>
            </select>
            <template v-else>{{
              value.note ? $t(`note.${value.note}`) : ""
            }}</template>
          </div>
          <div
            :class="{
              [voice]: true,
              voice: true,
              expanded: editable,
              clickable: editable && value.note,
            }"
            @click="editable && value.note ? (song.lead = voice) : false"
          >
            <span>
              {{ editable ? $t(voice) : $t(voice)[0] }}
              <Buzz
                v-if="(editable && value.note) || value.buzz"
                @click="editable ? (value.buzz = !value.buzz) : null"
                :active="value.buzz"
              />
            </span>
          </div>
          <div class="link">
            <input
              v-if="editable && value.note"
              type="text"
              :placeholder="$t('link')"
              v-model="value.link"
            />
            <template v-else-if="value.note">
              <audio v-if="getExtension(value.link)" controls preload="auto">
                <source
                  :type="`audio/${getExtension(value.link)}`"
                />
                <!-- fallback pour les navigateurs qui ne supportent pas la balise audio -->
                <a
                  :href="value.link"
                  target="_blank"
                  rel="noopener noreferrer"
                  >{{ value.link }}</a
                >
              </audio>
              <a
                v-else
                :href="value.link"
                target="_blank"
                rel="noopener noreferrer"
                >{{ value.link }}</a
              >
            </template>
          </div>
        </div>
      </transition>
    </template>
  </div>
</template>

<script>
import Buzz from "./Buzz.vue";

const getExtension = function(fileName) {
  let ext = fileName.split(".").pop();
  if (ext === "mp3") return "mpeg";
  if (ext.length === 3) return ext;
  return false;
};

export default {
  name: "NotesSelect",
  components: { Buzz },
  inject: ["song", "editable"],
  methods: {
    getExtension,
  },
};
</script>

