    padding: 1px;
    overflow: hidden;
    line-height: 8mm;
    &.lead .note {
      border: 2px solid black;
      line-height: calc(8mm - 4px);
    }
    &.v-enter-from,
    &.v-leave-to {
      opacity: 0;
      height: 0;
      .voice {
        width: 10mm !important;
      }
      .note {
        width: 8mm !important;
      }
    }
    .note {
      height: 8mm;
      width: 8mm;
      outline: 1px solid black;
      text-align: center;
      font-weight: bold;
      transition: width 0.5s;
