<template>
  <div id="piano">
    <template v-for="(octave, i) in 5" :key="i">
      <div
        v-for="(freqs, note) in $notes"
        :key="note"
        @mouseenter="$event.buttons === 1 ? playNote(freqs[octave]) : null"
        @mousedown="playNote(freqs[octave])"
        @mouseleave="stopNote()"
        @mouseup="stopNote()"
        :class="[
          'note',
          note.indexOf('#') == -1 ? 'white' : 'black',
          freqs[octave] === frequency ? 'active' : false,
        ]"
        :style="{
          background: colors[freqs[octave]] ? colors[freqs[octave]] : false,
        }"
      >
        {{ note.indexOf("#") !== -1 ? "♭" : $t(`note.${note}`) }}
      </div>
    </template>
  </div>
</template>

<script>
const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

export default {
  name: "Piano",
  props: ["colors"],
  data() {
    return {
      frequency: 0,
    };
  },
  methods: {
    playNote(frequency, to = false) {
      this.stopNote();
      this.frequency = frequency;
      this.oscillator = audioCtx.createOscillator();
      this.oscillator.type = this.wave;
      this.oscillator.frequency.value = frequency; // value in hertz
      let now = audioCtx.currentTime;
      if (to) {
        this.oscillator.frequency.setValueAtTime(frequency, now + 1);
        this.oscillator.frequency.exponentialRampToValueAtTime(to, now + 5);
      }
      this.oscillator.connect(audioCtx.destination);
      this.oscillator.start();
      if (to) {
        this.oscillator.stop(now + 7);
        this.oscillator.onended = this.stopNote;
      }

      let allFreq = Object.values(this.$notes).flat();

      this.interval = setInterval(() => {
        if (!this.oscillator) clearInterval(this.interval);
        else {
          let val = this.oscillator.frequency.value;
          this.frequency = allFreq.reduce((a, b) => {
            return Math.abs(b - val) < Math.abs(a - val) ? b : a;
          });
        }
      }, 50);
    },
    stopNote() {
      this.frequency = false;
      if (this.oscillator) {
        this.oscillator.stop();
        this.oscillator = false;
      }
    },
  },
};
</script>

