import Version from "./Version";
import Song from "./Song";

const API_KEY = "$2b$10$zReWz1szIyCTi6Ra6GT1pe2HFteJSR1vATxAce7QJzHP4H6m9zy3G";
const ID = "61f29ec41960493ad1836e2c";
const BASE = "https://api.jsonbin.io/v3";
const MAX_VER = 10;

let ajaxLoading;
const AJAX = ({ type, url, headers, onSuccess, onError, data }) => {
  let req = new XMLHttpRequest();
  req.onreadystatechange = () => {
    if (req.readyState == XMLHttpRequest.DONE) {
      ajaxLoading ? ajaxLoading(false) : null;
      if (req.status === 200 && onSuccess) {
        onSuccess(JSON.parse(req.responseText));
      } else if (req.status !== 200 && onError) {
        onError(JSON.parse(req.responseText));
      }
    }
  };
  req.open(type, url, true);
  req.setRequestHeader("X-Master-Key", API_KEY);
  for (const id in headers) {
    req.setRequestHeader(id, headers[id]);
  }
  req.send(data ? JSON.stringify(data) : "");
  ajaxLoading ? ajaxLoading(true) : null;
};

class JsonBin {
  songs = {};

  constructor() {}

  set onLoad(fct) {
    ajaxLoading = fct;
  }

  fetchSongs(lastId, onSuccess) {
    AJAX({
      type: "GET",
      url: `${BASE}/c/${ID}/bins/${lastId ? lastId : ""}`,
      onSuccess: onSuccess ? onSuccess : undefined,
    });
  }

  getSong(id, onSuccess) {
    AJAX({
      type: "GET",
      url: `${BASE}/b/${id}/latest`,
      onSuccess(res) {
        if (onSuccess) {
          onSuccess(res, new Version(res.record, Song));
        }
      },
    });
  }

  renameSong(id, name, onSuccess) {
    AJAX({
      type: "PUT",
      url: `${BASE}/b/${id}/meta/name`,
      headers: {
        "X-Bin-Name": name,
      },
      onSuccess(res) {
        if (onSuccess) {
          onSuccess(res, new Version(res.record, Song));
        }
      },
    });
  }

  deleteSong(id, onSuccess) {
    AJAX({
      type: "DELETE",
      url: `${BASE}/b/${id}`,
      onSuccess: onSuccess ? onSuccess : undefined,
    });
  }

  updateSong(id, versions, onSuccess) {
    let newVers = [...versions].filter(song => (song.lyrics && song.lyrics.length > 0));
    while (newVers.length > MAX_VER) {
      versions.shift();
    }
    newVers.push(new versions.type(versions.altered));
    AJAX({
      type: "PUT",
      url: `${BASE}/b/${id}`,
      data: newVers,
      headers: {
        "Content-Type": "application/json",
      },
      onSuccess(res) {
        if (onSuccess) {
          onSuccess(res, new Version(res.record, Song));
        }
      },
    });
  }

  createSong(title, onSuccess) {
    AJAX({
      type: "POST",
      url: `${BASE}/b`,
      data: new Version([{ title }], Song),
      headers: {
        "Content-Type": "application/json",
        "X-Collection-Id": ID,
        "X-Bin-Name": title,
      },
      onSuccess(res) {
        if (onSuccess) {
          onSuccess(res, new Version(res.record, Song));
        }
      },
    });
  }
}
export default new JsonBin();
