export default class Version extends Array {
  version = 0;
  altered = {};
  type = Object;

  constructor(versions, type = Object) {
    super();
    this.type = type;
    if (Array.isArray(versions)) {
      for (const i in versions) {
        this.push(new this.type(versions[i]));
      }
    } else {
      this.push(new this.type(versions));
    }
    this.version = this.length - 1;
    this.altered = new this.type(this[this.version]);
  }

  get latest() {
    return this[this.length - 1];
  }
  get versioning() {
    return this[this.version];
  }

  hasChanged() {
    return JSON.stringify(this.altered) !== JSON.stringify(this.latest);
  }

  initChange() {
    this.altered = new this.type(this.versioning);
  }

  previous() {
    if (this.hasPrevious()) this.version--;
  }

  next() {
    if (this.hasNext()) this.version++;
  }

  hasPrevious() {
    return this.version > 0;
  }

  hasNext() {
    return this.version < this.length - 1;
  }
}
