<template>
  <div
    ref="editable"
    :class="{ 'editable-div': true, editable }"
    :contenteditable="editable"
    @input="$emit('update:modelValue', $event.target.innerText)"
  />
</template>

<script>
export default {
  name: "EditableDiv",
  props: {
    modelValue: {
      type: String,
      default: "",
    },
    editable: {
      type: Boolean,
      default: true,
    },
  },
  mounted() {
    this.$refs.editable.innerText = this.modelValue;
  },
  watch: {
    modelValue(value) {
      const isSame = this.$refs.editable.innerText === value;
      if (isSame) return;
      this.$refs.editable.innerText = value;
    },
  },
};
</script>

<style lang="scss">
.editable-div {
  padding: 1mm;
  outline: 1px solid transparent;
  transition: 0.5s;
  p:first-of-type {
    margin-top: 0;
  }
  p:last-of-type {
    margin-bottom: 0;
  }
}
</style>