<template>
  <div id="theoryView">
    <div id="tabs">
      <button
        v-for="tab in ['Voices', 'Chords']"
        :key="tab"
        :class="['tab-button', { active: currentTab === tab }]"
        @click="currentTab = tab"
      >
        {{ tab }}
      </button>
    </div>
    <div>
      <label
        ><input v-model="wave" type="radio" value="sine" />Sinusoïdale</label
      >
      <label><input v-model="wave" type="radio" value="square" />Carré</label>
      <label
        ><input v-model="wave" type="radio" value="triange" />Triangle</label
      >
      <label
        ><input v-model="wave" type="radio" value="sawtooth" />Dent de
        scie</label
      >
    </div>
    <Piano ref="piano" :colors="freqColors" />
    <div class="tab">
      <div id="voices">
        <div
          v-for="({ from, to, color }, voice, i) in $voices"
          :style="{ 'border-color': color }"
          :class="['voice', voice]"
          :key="i"
        >
          <span
            @click="
              $refs.piano.playNote(
                $notes[from.note][from.octave],
                $notes[to.note][to.octave]
              )
            "
            >{{ $t(voice) }}</span
          >
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Piano from "../components/Piano.vue";

export default {
  name: "Theory",
  components: { Piano },
  data() {
    return {
      currentTab: "Voices",
      oscillator: false,
      frequency: false,
      wave: "sine",
    };
  },
  computed: {
    freqColors() {
      let colors = {};
      for (const voice in this.$voices) {
        const params = this.$voices[voice];
        let from = this.$notes[params.from.note][params.from.octave];
        let to = this.$notes[params.to.note][params.to.octave];
        colors[from] = this.$voices[voice].color;
        colors[to] = this.$voices[voice].color;
      }
      return colors;
    },
  },
};
</script>

