<template>
  <div v-if="editor" class="lyrics-editor-container">
    <BubbleMenu
      :editor="editor"
      class="bubble-menu"
      :tippy-options="{ duration: 100 }"
    >
      <template v-if="editable && song.getVoices().length > 0">
        <button
          class="grey"
          @click="
            editor
              .chain()
              .focus()
              .unsetAllMarks()
              .run()
          "
        >
          {{ $t("none") }}
        </button>
        <template v-for="voice in song.getVoices()" :key="voice">
          <button
            @click="toggleMark(voice)"
            :class="{ grey: true, active: editor.isActive(voice) }"
          >
            <span :class="voice">{{ $t(voice) }} </span>
          </button>
        </template>
      </template>
    </BubbleMenu>

    <div v-if="editable" ref="floatingMenu" class="floating-menu">
      <button
        v-for="section in $sections"
        :key="section"
        @click="toggleNode(section)"
        :class="{
          grey: true,
          active: editor.isActive('section', { type: section }),
        }"
      >
        {{ $t(section) }}
      </button>
    </div>

    <EditorContent :class="{ editable }" :editor="editor" />
  </div>
</template>

<script>
import {
  Editor,
  EditorContent,
  Mark,
  BubbleMenu,
  mergeAttributes,
} from "@tiptap/vue-3";
import Document from "@tiptap/extension-document";
import Paragraph from "@tiptap/extension-paragraph";
import Text from "@tiptap/extension-text";
import HardBreak from "@tiptap/extension-hard-break";
import History from "@tiptap/extension-history";

import Voices from "../classes/Voices";
import Sections from "../classes/Sections";

let voicesMark = [];
for (let voice in Voices) {
  voicesMark.push(
    Mark.create({
      name: voice,
      addOptions() {
        return { HTMLAttributes: { class: voice } };
      },
      parseHTML() {
        return [{ tag: `span.${voice}` }];
      },
      renderHTML({ HTMLAttributes }) {
        return [
          "span",
          mergeAttributes(this.options.HTMLAttributes, HTMLAttributes),
          0,
        ];
      },
    })
  );
}

const Section = Paragraph.extend({
  name: "section",
  addOptions() {
    return {
      types: Sections,
      HTMLAttributes: {},
    };
  },
  addAttributes() {
    return {
      type: {
        default: Sections[0],
        rendered: false,
      },
    };
  },
  parseHTML() {
    return this.options.types.map((type) => ({
      tag: `p.${type}`,
      attrs: { type },
    }));
  },
  renderHTML({ node, HTMLAttributes }) {
    const hasLevel = this.options.types.includes(node.attrs.type);
    const type = hasLevel ? node.attrs.type : this.options.types[0];

    return [
      `p`,
      mergeAttributes(this.options.HTMLAttributes, HTMLAttributes, {
        class: type,
      }),
      0,
    ];
  },
});

export default {
  name: "LyricsEditor",
  inject: ["song", "editable"],
  components: {
    EditorContent,
    BubbleMenu,
  },
  data() {
    return {
      editor: null,
    };
  },
  watch: {
    editable() {
      this.editor.setOptions({ editable: this.editable });
    },
    song: {
      deep: true,
      handler(value) {
        const isSame = this.editor.getHTML() === value.lyrics;
        if (isSame) return;
        this.editor.commands.setContent(value.lyrics, false);
      },
    },
  },
  mounted() {
    this.editor = new Editor({
      editable: this.editable,
      content: this.song.lyrics,
      extensions: [
        History,
        Document,
        Text,
        ...voicesMark,
        Section,
        HardBreak.extend({
          addKeyboardShortcuts() {
            return {
              Enter: () => this.editor.commands.setHardBreak(),
              "Shift-Enter": () => this.editor.commands.splitBlock(),
            };
          },
        }),
      ],
      editorProps: {
        transformPastedHTML: (html) => {
          let text = html.replace(/<[^>]+>/g, "<br>");
          while (text.indexOf("<br><br>") !== -1)
            text = text.replace("<br><br>", "<br>");
          var re = new RegExp(String.fromCharCode(160), "g");
          text = text.replace(re, "");
          return text;
        },
      },
      onUpdate: () => {
        this.song.lyrics = this.editor.getHTML();
      },
      onSelectionUpdate: () => {
        if (this.editable) {
          let curNode = getSelection().anchorNode;
          if (curNode.nodeName === "#text") {
            curNode = curNode.parentElement.closest("p");
          } else {
            curNode = curNode.closest("p");
          }
          let top =
            curNode.offsetTop +
            curNode.offsetHeight / 2 -
            this.$refs.floatingMenu.offsetHeight / 2;
          let left = this.$refs.floatingMenu.offsetWidth;
          this.$refs.floatingMenu.style.top = `${top}px`;
          this.$refs.floatingMenu.style.left = `-${left}px`;
        }
      },
    });
  },
  methods: {
    toggleMark(mark) {
      this.editor
        .chain()
        .focus()
        .toggleMark(mark)
        .run();
    },
    toggleNode(mark) {
      this.editor.commands.setNode("section", { type: mark });
    },
  },
  beforeUnmount() {
    this.editor.destroy();
  },
};
</script>

