<template>
  <Loader v-if="loading" />
  <div id="menu">
    <template v-for="(song, num) in songs" :key="song.id">
      <div>
        <router-link :to="{ name: 'song', params: { id: song.id } }">
          {{
            `${song.title}${new Array(31 - song.title.length).join(".")}${(
              "" +
              (num + 1)
            ).padStart(3, 0)}`
          }}
        </router-link>
      </div>
    </template>
  </div>

  <div id="footer">
    <button class="add" @click="createSong()">
      {{ $t("new_song") }}
    </button>
    <div>
      <router-link :to="{ name: 'theory' }">{{ $t("theory") }}</router-link>
    </div>
  </div>

  <div id="main">
    <router-view />
  </div>
</template>

<script>
import Loader from "./components/Loader.vue";
import JsonBin from "./classes/JsonBin";
import Swal from "sweetalert2";

export default {
  name: "App",
  components: { Loader },
  data() {
    return {
      loading: false,
      songsUnsorted: {},
    };
  },
  created() {
    JsonBin.onLoad = (load) => (this.loading = load);
    this.fetchSongs();
  },
  computed: {
    songs() {
      return Object.entries(this.songsUnsorted)
        .map((e) => {
          /* let title = e[1];
          const nonSortable = ["Les", "La", "Le", "L'", "Une", "Un", "Des"];
          for (const i in nonSortable) {
            let word = nonSortable[i];
            if (title.toLowerCase().indexOf(word.toLowerCase()) === 0) {
              title = title.substring(word.length) + ` (${word})`;
              break;
            }
          }*/
          return { id: e[0], title: e[1] };
        })
        .sort((a, b) => (a.title < b.title ? -1 : 1));
    },
  },
  methods: {
    fetchSongs(lastId = false) {
      JsonBin.fetchSongs(lastId, (res) => {
        for (let i in res) {
          this.songsUnsorted[res[i].record] = res[i].snippetMeta.name;
        }
        if (res.length === 10) {
          this.fetchSongs(res[9].record);
        }
      });
    },
    createSong() {
      Swal.fire({
        position: "top",
        title: "Quel est le nom de votre chant ?",
        input: "text",
        icon: "question",
        showCancelButton: true,
      }).then((result) => {
        if (result.isConfirmed) {
          JsonBin.createSong(result.value, (res) => {
            this.songsUnsorted[res.metadata.id] = res.metadata.name;
            this.$router.push({
              name: "song",
              params: { id: res.metadata.id },
            });
          });
        }
      });
    },
  },
};
</script>

